const sd = $getWorkflowStaticData('global');

const SYSTEM = `Tu es un traducteur expert pour le jeu Minecraft. Traduis en français les textes du tableau JSON fourni.
Chaque élément du tableau est une description de quête. Retourne UNIQUEMENT un tableau JSON avec le même nombre d'éléments, dans le même ordre, traduits en français.

Règles strictes :
- Conserve intégralement les balises § suivies d'un caractère (§0-9, §a-f, §l, §r, §o, §n, §m, §k)
- Conserve les balises HTML : <br/>, <br>, et les balises <a href="...">
- Conserve les balises [url]...[/url]
- Ne traduis pas les noms d'items Minecraft (ex: Diamond Pickaxe, Iron Ingot, Cobblestone)
- Ne traduis pas les noms de mods (ex: Thaumcraft, IndustrialCraft, Applied Energistics)
- Ne traduis pas les noms de biomes ou dimensions (ex: The Nether, The End)
- Réponds UNIQUEMENT avec le tableau JSON traduit, même nombre d'entrées, même ordre, sans markdown, sans commentaire`;

const questIds = [];
const texts = [];
for (const item of $input.all()) {
  questIds.push(item.json.quest_id);
  texts.push(item.json.data);
}

// Stocker l'ordre des quest_id pour le mapping dans Accumulate
sd.pendingQuestIds = questIds;

return [{
  json: {
    systemPrompt: SYSTEM,
    prompt: JSON.stringify(texts)
  }
}];

const sd = $getWorkflowStaticData('global');
if (!sd.translations) sd.translations = {};

const questIds = sd.pendingQuestIds || [];
const text = $input.first().json.message?.content ?? '';

const cleaned = text
  .replace(/^```json\s*/m, '')
  .replace(/^```\s*/m, '')
  .replace(/\s*```$/m, '')
  .trim();

try {
  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) {
    if (parsed.length !== questIds.length) {
      console.warn(`⚠️ Longueur différente : ${questIds.length} attendus, ${parsed.length} reçus`);
    }
    parsed.forEach((translation, i) => {
      if (questIds[i] !== undefined) {
        sd.translations[questIds[i]] = translation;
      }
    });
    console.log(`Accumulé : ${parsed.length} — total : ${Object.keys(sd.translations).length}`);
  } else {
    console.error('Réponse non-tableau:', typeof parsed);
    console.error('Reçu:', cleaned.substring(0, 200));
  }
} catch(e) {
  console.error('Erreur parsing:', e.message);
  console.error('Début reçu:', cleaned.substring(0, 300));
}

return $input.all();

const sd = $getWorkflowStaticData('global');
const all = sd.translations ?? {};
sd.translations = {};

console.log(`Total traduit : ${Object.keys(all).length} quêtes`);
return [{ json: all }];
